(window.webpackJsonp=window.webpackJsonp||[]).push([[95],{722:function(n,t){n.exports="\x3c!-- \ntitle: 01-Flutter入门\nsort: \n--\x3e \n\n## HelloWorld\n\n> [文档](https://api.flutter.dev/)\n\n```dart\nimport 'package:flutter/material.dart';\n\n// 入口函数\nvoid main() {\n  runApp(\n    new Center(\n      child: new Text(\n        'Hello, world!',\n        textDirection: TextDirection.ltr,\n      ),\n    ),\n  );\n}\n```\n\n### 调用类\n\n```dart\nimport 'package:flutter/material.dart';\n\n// 入口函数\nvoid main() => runApp(MyApp());\n\n// MyApp类\nclass MyApp extends StatelessWidget {\n  // 重写build方法\n  @override\n  Widget build(BuildContext context) {\n    // 返回一个Material风格的组件\n    return MaterialApp(\n      title: 'Welcome to Flutteraa',\n      // Scaffold: Material 布局结构\n      home: Scaffold(\n        // 创建一个Bar\n        appBar: AppBar(\n          title: Text('Welcome to Flutter'),\n        ),\n        // 主体添加一个hello world\n        body: Center(\n          child: Text('Hello World'),\n        ),\n      ),\n    );\n  }\n```\n\n"}}]);